from flask import Flask, jsonify, request
import os
import json
import time

app = Flask(__name__)
CACHE_DIR = 'cache'
os.makedirs(CACHE_DIR, exist_ok=True)

def get_cache_key(request):
    return hash(frozenset(request.args.items()))

def save_to_cache(key, data, expiration=3600):
    cache_file = os.path.join(CACHE_DIR, f'{key}.json')
    with open(cache_file, 'w') as f:
        json.dump({'data': data, 'timestamp': time.time() + expiration}, f)

def load_from_cache(key):
    cache_file = os.path.join(CACHE_DIR, f'{key}.json')
    if not os.path.exists(cache_file):
        return None
    with open(cache_file, 'r') as f:
        cached_data = json.load(f)
    if time.time() > cached_data['timestamp']:
        os.remove(cache_file)  # Cache expired, remove the file
        return None
    return cached_data['data']

@app.route('/api/expensive')
def expensive_api():
    cache_key = get_cache_key(request)
    cached_response = load_from_cache(cache_key)
    if cached_response:
        return jsonify(cached_response)

    # Simulate an expensive API call
    response_data = {
        'status': 'success',
        'data': {
            'nested': {'key1': 'value1', 'key2': [1, 2, 3]},
            'metadata': {'timestamp': time.time()}
        }
    }

    save_to_cache(cache_key, response_data)
    return jsonify(response_data)

if __name__ == '__main__':
    app.run(debug=True)